<?php
declare(strict_types=1);
namespace Ostoya\ShoppingList\Model\Resolver; use Magento\Framework\GraphQl\Config\Element\Field;use Magento\Framework\GraphQl\Exception\GraphQlInputException;use Magento\Framework\GraphQl\Exception\GraphQlNoSuchEntityException;use Magento\Framework\GraphQl\Query\ResolverInterface;use Magento\Framework\GraphQl\Schema\Type\ResolveInfo;use Magento\Framework\Exception\NoSuchEntityException;use Ostoya\ShoppingList\Model\Service\ShoppingListService;
class AddProductToShoppingList implements ResolverInterface{public function __construct(private readonly CustomerContext $customerContext,private readonly ShoppingListService $service,private readonly ResolverDataFormatter $formatter){} public function resolve(Field $field,$context,ResolveInfo $info,array $value=null,array $args=null): array{$in=$args['input'];if(empty($in['product_id'])&&empty($in['sku'])){throw new GraphQlInputException(__('Provide product_id or sku.'));}try{$item=$this->service->addItem($this->customerContext->getCustomerId($context),(int)$in['list_id'],isset($in['product_id'])?(int)$in['product_id']:null,$in['sku']??null,(float)($in['qty']??1),(string)($in['mode']??'SET_OR_INCREMENT'));$list=$this->service->getCustomerListById($this->customerContext->getCustomerId($context),(int)$item->getData('list_id'));return ['success'=>true,'message'=>'Product added to shopping list.','item'=>$this->formatter->formatItem($item),'list'=>$this->formatter->formatList($list,[])];}catch(NoSuchEntityException $e){throw new GraphQlNoSuchEntityException(__('Entity not found.'));}}}
